<?php declare(strict_types=1);
namespace App\Services;
final class LogService { public function write(string $level,string $message,array $context=[]):void { $line=json_encode(['time'=>gmdate('c'),'level'=>$level,'message'=>$message,'context'=>$context],JSON_UNESCAPED_SLASHES).PHP_EOL; $file=$this->file(); if(!is_dir(dirname($file)))mkdir(dirname($file),0750,true); file_put_contents($file,$line,FILE_APPEND|LOCK_EX); } public function recent(int $limit=100):array { $file=$this->file();if(!is_file($file))return [];return array_slice(array_reverse(file($file,FILE_IGNORE_NEW_LINES|FILE_SKIP_EMPTY_LINES)?:[]),0,$limit); } private function file():string{return rtrim(config('settings.log_directory'),'/').'/app-'.gmdate('Y-m-d').'.log';} public function info(string $m,array $c=[]):void{$this->write('info',$m,$c);} public function error(string $m,array $c=[]):void{$this->write('error',$m,$c);} }
